from pathlib import Path
import json
from collections import Counter

def identify_repeat_findings(findings_log: Path, n_audits: int = 2) -> list[dict]:
    """
    Identify findings (by check name + control_id) that appear
    in N or more consecutive mock audits — signals systemic root cause.
    """
    if not findings_log.exists():
        return []

    all_findings = []
    for line in findings_log.read_text().splitlines():
        if line.strip():
            all_findings.append(json.loads(line))

    # Key = (control_id, check_name)
    key_counts = Counter(
        (f.get("control_id", "UNKNOWN"), f.get("check", f.get("title", "unknown")))
        for f in all_findings
    )

    repeats = [
        {"control_id": k[0], "check": k[1], "occurrences": v}
        for k, v in key_counts.items()
        if v >= n_audits
    ]
    return sorted(repeats, key=lambda x: -x["occurrences"])

# Repeat findings require root cause analysis at the next MRC committee meeting
repeats = identify_repeat_findings(Path("evidence/mock_audit/findings.jsonl"), n_audits=2)
if repeats:
    print("REPEAT FINDINGS (systemic — require MRC escalation):")
    for r in repeats:
        print(f"  {r['control_id']} / {r['check']}: {r['occurrences']} occurrences")
